-- ============================================================
-- IMPORTACAO: avaliacao TSM da GMining/Brazauro (Tocantinzinho)
-- a partir dos 9 arquivos HBR101550001-GMN-RT001_R1_APENDICE_II_TSM_*.xlsx
-- Pre-requisito: catalog_tsm.sql ja executado (34 requisitos em standard_requirements, standard_id=2)
-- Metodologia: aderencia por indicador calculada por barragem a partir dos criterios
-- (media dos valores 'Aderencia' por criterio nas planilhas '4/5/6... INDICADOR N'),
-- convertida para os 4 niveis do app por faixa (definido com o cliente em 2026-07-10):
--   >= 90%  -> Totalmente Conforme (100)
--   >= 75%  -> Conforme (75)
--   >= 50%  -> Parcialmente Conforme (50)
--   <  50%  -> Nao Conforme (0)
-- O nivel de maturidade declarado (C/B/A/AA/AAA) por indicador (aba '2. NIVEL DE
-- DESEMPENHO') e o mesmo para as 3 barragens (o arquivo nao o discrimina por estrutura).
begin;
with assessor as (
  select id as assessed_by from profiles where role in ('hidrobr_admin','hidrobr_consultant') order by created_at limit 1
),
raw(facility_id, requirement_code, status, score, score_value, assessment_text, maturity_level) as (
