resolved as (
  select '637aa7f4-5332-4a1d-946f-9ab77219fde4'::uuid as cycle_id, raw.facility_id, sr.id as requirement_id,
    raw.status, raw.score, raw.score_value, raw.assessment_text, raw.maturity_level
  from raw
  join standard_requirements sr on sr.code = raw.requirement_code and sr.standard_id = 2
),
inserted_responses as (
  insert into tsm_responses (cycle_id, facility_id, requirement_id, status, implementation_text, submitted_at)
  select resolved.cycle_id, resolved.facility_id, resolved.requirement_id, resolved.status,
    'Importado da avaliacao tecnica HIDROBR (doc. HBR101550001-GMN-RT001, Rev.1, 08/07/2026, Apendice II TSM).',
    now()
  from resolved
  returning id, facility_id, requirement_id
)
insert into tsm_assessments (response_id, assessed_by, score, score_value, assessment_text, maturity_level, published_at)
select ir.id, (select assessed_by from assessor), res.score, res.score_value, res.assessment_text, res.maturity_level,
  '2026-07-08 00:00:00-03'::timestamptz
from inserted_responses ir
join resolved res on res.facility_id = ir.facility_id and res.requirement_id = ir.requirement_id;
